+        let report = lab.run_with_setup(|runtime, root| {
+            let (t1, _) = FsLab::spawn_named(runtime, root, "mp_sl", async {
+                let sl = SeqLock::new(0);
+                sl.write(5);
+                sl.read("mp").unwrap_or(0)
+            });
+            let (t2, _) = FsLab::spawn_named(runtime, root, "mp_lr", async {
