+        let mut explored = 0u32;
+        let mut all_pass = true;
+        for seed in 0..10 {
+            let lab = FsLab::new(seed).worker_count(2).max_steps(5_000);
+            let report = lab.run_single_task(async move {
+                let lr = LeftRight::new(0);
