+            explored += 1;
+        }
+        results.push(TestResult {
+            name: "schedule_exploration",
+            pass: all_pass && explored >= 10,
+            detail: format!("explored={explored}"),
+        });
+    }
+
+    // 6. Trace certificate non-zero
+    {
