+
+fn update_max(metric: &AtomicU64, val: u64) {
+    let mut prev = metric.load(Ordering::Relaxed);
+    while val > prev {
+        match metric.compare_exchange_weak(prev, val, Ordering::Relaxed, Ordering::Relaxed) {
+            Ok(_) => break,
+            Err(actual) => prev = actual,
+        }
+    }
+}
